import React, { useRef, useState } from "react";
import { WA_LINK } from "../../data/constants";

const API_URL = "http://localhost:5000/api/applications";

export default function ApplyForm({ job, onBack }) {
  const [done, setDone]     = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError]   = useState("");
  const [form, setForm]     = useState({ name: "", email: "", phone: "", exp: "", cover: "", file: null });
  const fileRef             = useRef(null);

  const submit = async () => {
    if (!form.name || !form.email || !form.phone) { alert("Please fill Name, Email and Phone!"); return; }
    setLoading(true);
    setError("");
    try {
      const data = new FormData();
      data.append("name", form.name);
      data.append("email", form.email);
      data.append("phone", form.phone);
      data.append("position", job.title);
      data.append("experience", form.exp);
      data.append("message", form.cover);
      if (form.file) data.append("resume", form.file);

      const res = await fetch(API_URL, { method: "POST", body: data });
      const json = await res.json();

      if (json.success) { setDone(true); }
      else { setError("Something went wrong. Please try again."); }
    } catch (err) {
      setError("Server error. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  if (done) return (
    <div style={{ textAlign: "center", padding: "clamp(40px,5vw,64px) 24px", background: "#fff", borderRadius: 28, boxShadow: "0 8px 48px rgba(2,132,199,.1)", border: "1px solid #EEF2FF" }}>
      <div style={{ width: 88, height: 88, borderRadius: "50%", background: "linear-gradient(135deg,#38BDF8,#0284C7)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 40, margin: "0 auto 28px", color: "#fff" }}>✓</div>
      <h2 style={{ fontSize: "clamp(24px,4vw,36px)", fontWeight: 900, color: "#0F172A", marginBottom: 10, letterSpacing: -0.8 }}>Application Submitted!</h2>
      <p style={{ color: "#64748B", fontSize: 15, marginBottom: 8, fontWeight: 400 }}>Thank you, <strong style={{ color: "#0F172A" }}>{form.name}</strong>!</p>
      <p style={{ color: "#64748B", fontSize: 14, marginBottom: 32, fontWeight: 400 }}>We'll contact you at <strong>{form.phone || form.email}</strong> within <strong style={{ color: "#0284C7" }}>24 hours</strong>.</p>
      <div style={{ display: "flex", gap: 12, justifyContent: "center", flexWrap: "wrap" }}>
        <button className="btn-primary" onClick={onBack}>Apply for Another Role</button>
        <a href={`${WA_LINK}?text=Hi, I applied for: ${job.title}`} target="_blank" rel="noreferrer">
          <button className="btn-whatsapp">💬 WhatsApp Resume</button>
        </a>
      </div>
    </div>
  );

  return (
    <>
      <div style={{ background: "linear-gradient(135deg,#0284C7,#075985)", borderRadius: 18, padding: "20px 26px", marginBottom: 28 }}>
        <div style={{ fontWeight: 900, fontSize: "clamp(16px,2vw,20px)", color: "#fff", marginBottom: 5 }}>{job.title}</div>
        <div style={{ fontSize: 13, color: "rgba(186,230,253,.88)", fontWeight: 500 }}>{job.dept} Position · Navi Mumbai / PAN India</div>
      </div>

      <div style={{ background: "#fff", borderRadius: 26, padding: "clamp(24px,4vw,44px)", boxShadow: "0 4px 40px rgba(2,132,199,.08)", border: "1px solid #EEF2FF", borderTop: "5px solid #0284C7" }}>
        <h2 style={{ fontSize: "clamp(20px,3vw,28px)", fontWeight: 900, color: "#0F172A", marginBottom: 6, letterSpacing: -0.5 }}>Apply for This Role</h2>
        <p style={{ fontSize: 13.5, color: "#64748B", marginBottom: 24, fontWeight: 400 }}>Fill your details — our team will reach out within 24 hours.</p>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(200px,1fr))", gap: 14, marginBottom: 14 }}>
          {[["name","Full Name *"], ["email","Email Address *"], ["phone","Phone Number *"], ["exp","Years of Experience"]].map(([k, pl]) => (
            <div key={k}>
              <label style={{ display: "block", fontSize: 10, color: "#94A3B8", fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>{pl}</label>
              <input className="inp" placeholder={pl} value={form[k]} onChange={e => setForm({ ...form, [k]: e.target.value })} />
            </div>
          ))}
        </div>

        <div style={{ marginBottom: 14 }}>
          <label style={{ display: "block", fontSize: 10, color: "#94A3B8", fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>Applying For</label>
          <input className="inp" value={job.title} readOnly style={{ background: "#F0F9FF", color: "#0284C7", fontWeight: 700 }} />
        </div>

        <div style={{ marginBottom: 14 }}>
          <label style={{ display: "block", fontSize: 10, color: "#94A3B8", fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>Cover Message</label>
          <textarea className="inp" rows={4} style={{ resize: "vertical" }} placeholder="Why are you a great fit?" value={form.cover} onChange={e => setForm({ ...form, cover: e.target.value })} />
        </div>

        <div style={{ marginBottom: 24 }}>
          <label style={{ display: "block", fontSize: 10, color: "#94A3B8", fontWeight: 900, letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>Upload Resume</label>
          <div
            onClick={() => fileRef.current?.click()}
            style={{ border: "2px dashed #BAE6FD", borderRadius: 14, padding: 24, textAlign: "center", cursor: "pointer", background: "#F8FAFF", transition: "all .2s" }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = "#0284C7"; e.currentTarget.style.background = "#EFF9FF"; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = "#BAE6FD"; e.currentTarget.style.background = "#F8FAFF"; }}
          >
            {form.file
              ? <div style={{ color: "#22C55E", fontWeight: 800, fontSize: 14 }}>✓ {form.file.name}</div>
              : <><div style={{ fontSize: 28, marginBottom: 6 }}>📎</div><div style={{ color: "#64748B", fontSize: 13, fontWeight: 700 }}>Click to Upload Resume</div><div style={{ color: "#94A3B8", fontSize: 11.5, marginTop: 3 }}>PDF, DOC, DOCX · Max 5MB</div></>
            }
          </div>
          <input ref={fileRef} type="file" accept=".pdf,.doc,.docx" style={{ display: "none" }} onChange={e => setForm({ ...form, file: e.target.files[0] || null })} />
        </div>

        {error && (
          <div style={{ background: "#FEF2F2", border: "1px solid #FECACA", borderRadius: 10, padding: "12px 16px", marginBottom: 16, color: "#DC2626", fontSize: 13, fontWeight: 600 }}>
            ⚠️ {error}
          </div>
        )}

        <div style={{ background: "#FFFBEB", borderRadius: 12, padding: "12px 17px", marginBottom: 22, display: "flex", gap: 10, alignItems: "center", border: "1px solid #FDE68A" }}>
          <span>💡</span>
          <span style={{ fontSize: 13, color: "#92400E", fontWeight: 500 }}>You can also WhatsApp your resume to <strong>+91 9869043500</strong></span>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))", gap: 12 }}>
          <button className="btn-primary" style={{ justifyContent: "center", padding: 14, fontSize: 14, opacity: loading ? 0.7 : 1 }} onClick={submit} disabled={loading}>
            {loading ? "Submitting..." : "Submit Application →"}
          </button>
          <a href={`${WA_LINK}?text=Hi, I want to apply for: ${job.title}`} target="_blank" rel="noreferrer" style={{ display: "block" }}>
            <button className="btn-whatsapp" style={{ width: "100%", justifyContent: "center", padding: 14, fontSize: 14, borderRadius: 13 }}>💬 Apply via WhatsApp</button>
          </a>
        </div>
      </div>
    </>
  );
}